import { useEffect, type RefObject } from 'react';

const SCROLL_THRESHOLD_PX = 10;
const TOP_SHOW_PX = 24;

/** Báo Nav ẩn/hiện topbar theo hướng scroll trong shell form (event `linm:nav:topbar-autohide`). */
export function useTopbarAutoHideOnScroll(
  scrollRef: RefObject<HTMLElement | null>,
  enabled = true,
): void {
  useEffect(() => {
    if (!enabled) return undefined;

    const el = scrollRef.current;
    if (!el) return undefined;

    let lastY = el.scrollTop;
    let ticking = false;

    const emit = (hidden: boolean) => {
      window.dispatchEvent(
        new CustomEvent('linm:nav:topbar-autohide', { detail: { hidden } }),
      );
    };

    const onScroll = () => {
      if (ticking) return;
      ticking = true;
      window.requestAnimationFrame(() => {
        const y = el.scrollTop;
        const delta = y - lastY;

        if (y <= TOP_SHOW_PX) {
          emit(false);
        } else if (delta > SCROLL_THRESHOLD_PX) {
          emit(true);
        } else if (delta < -SCROLL_THRESHOLD_PX) {
          emit(false);
        }

        lastY = y;
        ticking = false;
      });
    };

    el.addEventListener('scroll', onScroll, { passive: true });

    return () => {
      el.removeEventListener('scroll', onScroll);
      emit(false);
    };
  }, [scrollRef, enabled]);
}
